import{_ as e,c as i}from"./app.90a21e26.js";const a={},l=i('<h1 id="ul-sfep" tabindex="-1"><a class="header-anchor" href="#ul-sfep" aria-hidden="true">#</a> UL SFEP</h1><p>Sales Force Empowerment Platform</p><p>A unified platform empowering both UL internal &amp; external users to imporve Sales Force capabilities and achieve performance excellence store execution.</p><h2 id="\u8BBF\u5E97\u667A\u80FD\u5316" tabindex="-1"><a class="header-anchor" href="#\u8BBF\u5E97\u667A\u80FD\u5316" aria-hidden="true">#</a> \u8BBF\u5E97\u667A\u80FD\u5316</h2><p>Visit Intelligence</p><h3 id="\u95E8\u5E97\u4E3B\u6570\u636E\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u95E8\u5E97\u4E3B\u6570\u636E\u7BA1\u7406" aria-hidden="true">#</a> \u95E8\u5E97\u4E3B\u6570\u636E\u7BA1\u7406</h3><p>Store Master Data Management Enabled store master data management for sales force, including: 1)Store master data set-up (information includes store, customer, sold to and etc.) 2)Store master data upload by batch</p><ul><li><p>\u5EFA\u7ACB\u4E3B\u6570\u636E</p><p>includes store, customer, sold to and etc. \u95E8\u5E97\u3001\u7ECF\u9500\u5546\u3001\u8BA2\u8D27\u90E8\u95E8...</p><ul><li>store</li><li>customer</li><li>sold to</li><li>\u5176\u4ED6\u3002\u3002</li></ul></li><li><p>\u6279\u91CF\u4E0A\u4F20</p></li></ul><h3 id="\u8BBF\u5E97\u6574\u4F53\u89C2-\u5927\u5C4F\u3001\u9A7E\u9A76\u8231" tabindex="-1"><a class="header-anchor" href="#\u8BBF\u5E97\u6574\u4F53\u89C2-\u5927\u5C4F\u3001\u9A7E\u9A76\u8231" aria-hidden="true">#</a> \u8BBF\u5E97\u6574\u4F53\u89C2\uFF08\u5927\u5C4F\u3001\u9A7E\u9A76\u8231\uFF09</h3><p>Visiting Holistic View A high-level display of visiting guideline including:</p><ol><li>DT/Store performance diagnosis in a holistic view</li><li>Consolidated UL Policies from Customer Portal</li><li>KPI Completion Rate</li><li>Auditing Status</li><li>Abnormal alert &amp; task list</li></ol><ul><li>\u7ECF\u9500\u5546\u7684\u7EE9\u6548\u8BCA\u65AD</li><li>\u95E8\u5E97\u7684\u7EE9\u6548\u8BCA\u65AD</li><li>\u6574\u5408\u7684UL\u7684\u653F\u7B56\u7B56\u7565\uFF08\u4ECECEP\u6765\uFF09</li><li>KPI\u5B8C\u6210\u7387</li><li>\u5BA1\u8BA1\u7684\u72B6\u6001</li><li>\u4EFB\u52A1\u5217\u8868</li><li>\u5F02\u5E38\u62A5\u8B66</li></ul><h3 id="\u8BBF\u5E97\u68C0\u67E5\u8868" tabindex="-1"><a class="header-anchor" href="#\u8BBF\u5E97\u68C0\u67E5\u8868" aria-hidden="true">#</a> \u8BBF\u5E97\u68C0\u67E5\u8868</h3><p>Visiting Check List Role-based visiting check list to guide a step by step in-store execution</p><ul><li>\u6309\u89D2\u8272\u5212\u5206</li></ul><h3 id="\u5E97\u5185\u56FE\u7247\u91C7\u96C6\u3001\u8BC6\u522B\u3001\u5B58\u50A8\u548C\u5C55\u793A" tabindex="-1"><a class="header-anchor" href="#\u5E97\u5185\u56FE\u7247\u91C7\u96C6\u3001\u8BC6\u522B\u3001\u5B58\u50A8\u548C\u5C55\u793A" aria-hidden="true">#</a> \u5E97\u5185\u56FE\u7247\u91C7\u96C6\u3001\u8BC6\u522B\u3001\u5B58\u50A8\u548C\u5C55\u793A</h3><p>Image Recognition &amp; Display Enabled in-store image capture, recognition, storage &amp; display, including the image collected by PMR to be shared to SR</p><ul><li>SR</li><li>PMR</li></ul><h3 id="\u8865\u8D27\u5355" tabindex="-1"><a class="header-anchor" href="#\u8865\u8D27\u5355" aria-hidden="true">#</a> \u8865\u8D27\u5355</h3><p>Replenishment Order</p><ol><li>Auto-fill replenishment order based on historical order and store demand forecasting</li><li>One step check-out based on replenishment order instead of adding SKU one by one</li></ol><ul><li><p>\u81EA\u52A8\u751F\u4EA7\u8865\u8D27\u5355</p></li><li><p>\u5386\u53F2\u8BA2\u5355\u9500\u552E\u60C5\u51B5</p><ul><li>\u4ECE\u54EA\u91CC\u6765\uFF1F</li></ul></li><li><p>\u8BA2\u5355\u9884\u6D4B\u60C5\u51B5</p><ul><li>\u4ECE\u54EA\u513F\u6765\uFF1F</li></ul></li><li><p>\u4E00\u952Echeck-out</p><p>One step check-out based on replenishment order instead of adding SKU one by one</p></li></ul><h3 id="\u52A8\u6001\u62DC\u8BBF\u8BA1\u5212" tabindex="-1"><a class="header-anchor" href="#\u52A8\u6001\u62DC\u8BBF\u8BA1\u5212" aria-hidden="true">#</a> \u52A8\u6001\u62DC\u8BBF\u8BA1\u5212</h3><p>Dynamic Route Planning</p><ol><li>PJP rule setting based on pre-aligned business rules with flexibility for rule adjustment per business requirements</li><li>Personalized PJP scheduling recommendations for different users</li><li>Enabled visiting alert for each store: i.e. hot leads, store without first order and etc.</li><li>Enabled flexibility for users to adjust the PJP per his/her own needs</li><li>PJP optimization recommendations based on historical record</li></ol><ul><li><p>\u56FA\u5B9A\u62DC\u8BBF\u89C4\u5219</p><ul><li>\u6839\u636E\u4E1A\u52A1\u7EA6\u5B9A\u81EA\u52A8\u751F\u6210\u3001\u53EF\u6839\u636E\u5B9E\u9645\u4E1A\u52A1\u8C03\u6574</li></ul></li><li><p>\u56FA\u5B9A\u62DC\u8BBF\u8BA1\u5212\u5EFA\u8BAE</p><ul><li>\u5343\u4EBA\u5343\u9762</li></ul></li><li><p>\u62DC\u8BBF\u63D0\u9192</p><ul><li>by store</li><li>hot leads\u3001store without first order and etc.</li></ul></li><li><p>\u4E2A\u4EBA\u6839\u636E\u5B9E\u9645\u60C5\u51B5\u8C03\u6574\u56FA\u5B9A\u62DC\u8BBF\u8BA1\u5212</p></li><li><p>\u57FA\u4E8E\u62DC\u8BBF\u5386\u53F2\u8BB0\u5F55\u7684\u4F18\u5316\u5EFA\u8BAE</p></li></ul><h3 id="tpm-activities" tabindex="-1"><a class="header-anchor" href="#tpm-activities" aria-hidden="true">#</a> TPM Activities</h3><p>Application</p><p>TPM Activities Application Enabled application (POSM &amp; PMG) &amp; approval request in Sales Force Empowerment Platform and synchronize these info to TPM for approval;</p><p>The approval result will be synchronized to Sales Force Empowerment Platform</p><ul><li>Enabled application (POSM &amp; PMG) &amp; approval request</li><li>\u5C06\u7533\u8BF7\u540C\u6B65\u5230TPM</li><li>\u5C06TPM\u7684\u5BA1\u6279\u7ED3\u679C\u540C\u6B65\u56DE\u6765</li></ul><h3 id="posm\u7269\u6599\u4FE1\u606F\u8DDF\u8E2A" tabindex="-1"><a class="header-anchor" href="#posm\u7269\u6599\u4FE1\u606F\u8DDF\u8E2A" aria-hidden="true">#</a> POSM\u7269\u6599\u4FE1\u606F\u8DDF\u8E2A</h3><p>POSM Logistics Tracking Enabled POSM logistics/delivery status tracking</p><ul><li>\u7269\u6D41\u72B6\u6001\u8DDF\u8E2A</li><li>\u4EA4\u4ED8\u72B6\u6001\u8DDF\u8E2A</li></ul><h3 id="\u4FC3\u9500\u5458\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u4FC3\u9500\u5458\u7BA1\u7406" aria-hidden="true">#</a> \u4FC3\u9500\u5458\u7BA1\u7406</h3><p>PMG Management Access PMG Management module (including PMG check-in check out, image storage and display and etc.) via Sales Force Empowerment Platform for more effective collaboration between SR and PMG</p><ul><li>check-in</li><li>check-out</li><li>image storage</li><li>display</li><li>\u5176\u4ED6\u3002\u3002</li></ul><h2 id="\u9500\u552E\u667A\u80FD\u5316" tabindex="-1"><a class="header-anchor" href="#\u9500\u552E\u667A\u80FD\u5316" aria-hidden="true">#</a> \u9500\u552E\u667A\u80FD\u5316</h2><p>Sales Intelligence</p><h3 id="\u8D44\u6599\u4E2D\u5FC3" tabindex="-1"><a class="header-anchor" href="#\u8D44\u6599\u4E2D\u5FC3" aria-hidden="true">#</a> \u8D44\u6599\u4E2D\u5FC3</h3><p>CD Content Hub/ Sales Library</p><p>Unilever\u2019s Official Content Hub which comprises ready-to-use contents (Corporate profile, product brochures, video and poster etc.) for DSR/SR to easily leverage on</p><ul><li>\u516C\u53F8\u4ECB\u7ECD</li><li>\u4EA7\u54C1\u5BA3\u4F20\u518C</li><li>\u89C6\u9891</li><li>\u6D77\u62A5</li><li>\u5176\u4ED6\u3002\u3002</li></ul><h3 id="\u9500\u552E\u5C0F\u5DE5\u5177" tabindex="-1"><a class="header-anchor" href="#\u9500\u552E\u5C0F\u5DE5\u5177" aria-hidden="true">#</a> \u9500\u552E\u5C0F\u5DE5\u5177</h3><p>Sales Toolkit</p><p>Unilever\u2019s official sales toolkit which comprises: selling story, profit analysis calculator, competitor comparison information and etc. for DSR/SR to easily leverage on</p><ul><li>\u9500\u552E\u6545\u4E8B</li><li>\u5229\u6DA6\u5206\u6790\u8BA1\u7B97\u5668</li><li>\u7ADE\u54C1\u6BD4\u8F83\u4FE1\u606F</li><li>\u5176\u4ED6\u3002\u3002</li></ul><h3 id="\u667A\u80FD\u5EFA\u8BAE" tabindex="-1"><a class="header-anchor" href="#\u667A\u80FD\u5EFA\u8BAE" aria-hidden="true">#</a> \u667A\u80FD\u5EFA\u8BAE</h3><p>Smart Proposal</p><p>Automatically mapping with ticked task &amp; sales insight with recommended content per store tagging\xA0(product brochure, videos, profit analysis)\xA0in a well-structured framework, which allows DSR/SR to leverage on for store visit</p><ul><li>Automatically mapping with ticked task &amp; sales insight with recommended content per store tagging (product brochure, videos, profit analysis) in a well-structured framework, which allows DSR/SR to leverage on for store visit</li></ul><h3 id="\u5B9A\u5236\u5316\u7684\u9500\u552E\u5EFA\u8BAE" tabindex="-1"><a class="header-anchor" href="#\u5B9A\u5236\u5316\u7684\u9500\u552E\u5EFA\u8BAE" aria-hidden="true">#</a> \u5B9A\u5236\u5316\u7684\u9500\u552E\u5EFA\u8BAE</h3><p>Smart Proposal</p><p>Automatically mapping with ticked task &amp; sales insight with recommended content per store tagging\xA0(product brochure, videos, profit analysis)\xA0in a well-structured framework, which allows DSR/SR to leverage on for store visit</p><ul><li>\u6839\u636E\u95E8\u5E97\u7684\u5386\u53F2\u8868\u73B0\u63D0\u4F9B\u4E2A\u6027\u5316\u9500\u552E\u610F\u89C1</li></ul><h2 id="\u4EFB\u52A1\u81EA\u52A8\u5316" tabindex="-1"><a class="header-anchor" href="#\u4EFB\u52A1\u81EA\u52A8\u5316" aria-hidden="true">#</a> \u4EFB\u52A1\u81EA\u52A8\u5316</h2><p>Task Automation</p><h3 id="\u81EA\u52A8\u4EFB\u52A1\u5206\u914D\u5668" tabindex="-1"><a class="header-anchor" href="#\u81EA\u52A8\u4EFB\u52A1\u5206\u914D\u5668" aria-hidden="true">#</a> \u81EA\u52A8\u4EFB\u52A1\u5206\u914D\u5668</h3><p>Automatic Task Allocator</p><p>Tasks created by upper management can be automatically assigned to relevant SR/DSR based on pre-configured setting</p><ul><li>pre-configured setting</li><li>\u4E0A\u7EA7\u521B\u5EFA\u540E\u81EA\u52A8\u53D1\u9001</li></ul><h3 id="\u4EFB\u52A1\u770B\u677F\u548C\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u4EFB\u52A1\u770B\u677F\u548C\u7BA1\u7406" aria-hidden="true">#</a> \u4EFB\u52A1\u770B\u677F\u548C\u7BA1\u7406</h3><p>Task Board &amp; Task Management</p><ol><li>Task display with prioritization</li><li>Task reminder</li><li>Task Status Tracking (completion, performance tracking, bonus &amp; incentive achievement)</li></ol><ul><li><p>\u4EFB\u52A1\u7684\u4F18\u5148\u7EA7</p></li><li><p>\u4EFB\u52A1\u63D0\u9192</p></li><li><p>\u4EFB\u52A1\u72B6\u6001\u8DDF\u8E2A</p><ul><li>\u6253\u5F00\u3001\u8FDB\u884C\u3001\u5B8C\u6210\u7B49</li><li>\u7EE9\u6548\u8DDF\u8E2A</li><li>\u5956\u91D1\u8DDF\u8E2A</li><li>\u6FC0\u52B1\u8FBE\u6210</li></ul></li></ul><h3 id="\u81EA\u52A8\u98CE\u9669\u9884\u8B66" tabindex="-1"><a class="header-anchor" href="#\u81EA\u52A8\u98CE\u9669\u9884\u8B66" aria-hidden="true">#</a> \u81EA\u52A8\u98CE\u9669\u9884\u8B66</h3><p>Automatic Risk Alert</p><p>Automatic risk alert is enabled for tasks with pre-configured rules</p><ul><li>pre-configured rules</li></ul><h3 id="\u884C\u52A8\u5EFA\u8BAE" tabindex="-1"><a class="header-anchor" href="#\u884C\u52A8\u5EFA\u8BAE" aria-hidden="true">#</a> \u884C\u52A8\u5EFA\u8BAE</h3><p>Action Recommendation</p><p>Detailed action recommendation per task based on task completion status and customer profile update</p><ul><li><p>\u8BE6\u7EC6\u7684\u5EFA\u8BAE</p></li><li><p>\u6839\u636E\u4EFB\u52A1\u5B8C\u6210\u60C5\u51B5</p></li><li><p>\u6839\u636Ecustomer\u8D44\u6599\u66F4\u65B0\u60C5\u51B5</p><ul><li>\u7EBF\u7D22\u7BA1\u7406\uFF1F\uFF1F</li></ul></li></ul><h2 id="\u975E\u529F\u80FD\u6027\u9700\u6C42" tabindex="-1"><a class="header-anchor" href="#\u975E\u529F\u80FD\u6027\u9700\u6C42" aria-hidden="true">#</a> \u975E\u529F\u80FD\u6027\u9700\u6C42</h2><h3 id="multi-frontend-supportive" tabindex="-1"><a class="header-anchor" href="#multi-frontend-supportive" aria-hidden="true">#</a> Multi-frontend supportive</h3><p>Platform must be front-end &amp; back-end decoupled and support multiple frontends, i.e. PC, mobile (APPs, WeChat Mini program, etc.)</p><h3 id="optimized-user-experience" tabindex="-1"><a class="header-anchor" href="#optimized-user-experience" aria-hidden="true">#</a> Optimized User Experience</h3><p>Style-unified, user-friendly and easy-to-use user experience</p><h3 id="adaptability-to-surrounding-systems" tabindex="-1"><a class="header-anchor" href="#adaptability-to-surrounding-systems" aria-hidden="true">#</a> Adaptability to surrounding systems</h3><p>Support integration with multiple surrounding systems with mature and stable integration solutions; SSO supported for embedded system access</p><h3 id="flexibility-and-scalability" tabindex="-1"><a class="header-anchor" href="#flexibility-and-scalability" aria-hidden="true">#</a> Flexibility and Scalability</h3><p>Platform must not be closed ecosystem and must allow functional enhancement and new module extension development; Container based</p><h3 id="micro-service-based-architecture" tabindex="-1"><a class="header-anchor" href="#micro-service-based-architecture" aria-hidden="true">#</a> Micro-service based architecture</h3><p>Platform need to be micro-service architecture based</p><h3 id="open-architecture" tabindex="-1"><a class="header-anchor" href="#open-architecture" aria-hidden="true">#</a> Open architecture</h3><p>Platform must be open and can be well integrated and adaptable with both internal systems (ERP/DMS/\u2026) and external ecosystem (JD/Taobao/Meituan/Alipay/China local LBS/\u2026)</p><h3 id="performance" tabindex="-1"><a class="header-anchor" href="#performance" aria-hidden="true">#</a> Performance</h3><p>Real-time or semi-real-time response for transactions; high usability and stability</p><h3 id="data-hosting" tabindex="-1"><a class="header-anchor" href="#data-hosting" aria-hidden="true">#</a> Data Hosting</h3><p>Data needs to be hosted in China</p><h3 id="successful-practices" tabindex="-1"><a class="header-anchor" href="#successful-practices" aria-hidden="true">#</a> Successful Practices</h3><p>The product modules must have existing successful practices for FMCG in China</p><h3 id="drp-design-and-plan" tabindex="-1"><a class="header-anchor" href="#drp-design-and-plan" aria-hidden="true">#</a> DRP design and plan</h3><p>There&#39;s a consolidated disaster recovery plan in place as the assurance for system performance</p><h3 id="incident-process" tabindex="-1"><a class="header-anchor" href="#incident-process" aria-hidden="true">#</a> Incident Process</h3><p>Defined communication line and approaches for incident management</p><h2 id="\u6570\u636E\u96C6\u6210" tabindex="-1"><a class="header-anchor" href="#\u6570\u636E\u96C6\u6210" aria-hidden="true">#</a> \u6570\u636E\u96C6\u6210</h2><p>Integration Requirements</p><h3 id="\u83B7\u53D6" tabindex="-1"><a class="header-anchor" href="#\u83B7\u53D6" aria-hidden="true">#</a> \u83B7\u53D6</h3><ul><li><p>Customer Enablement Platform</p><p>A distributor super entry to comprehensively enable distributors &amp; Unilever engagements efficiency, effectiveness &amp; experience</p><ul><li>Distributor related policies</li><li>Affair processing status</li></ul></li><li><p>Digital Selling Platform</p><p>Unified platform for store to engage with brand directly, enable store\u2019s self-ordering services and empower in-store retailing via O2O &amp; CGB</p><ul><li>UL self-ordering records</li><li>store retailing performances</li><li>other engagement info</li></ul></li><li><p>TPM</p><p>Trade promotion management platform for activities arrangements, budget control, cost estimation and etc.</p><ul><li>Trade marketing related info</li><li>activities scheduling execution status</li><li>application approval status</li><li>application (POSM &amp; PMG) &amp; approval status</li><li>\u5176\u4ED6\u3002\u3002</li></ul></li><li><p>POSM</p><p>Online platform for POSM management: application, logistic tracking, In-store POSM management</p><ul><li>sales materials application related info</li></ul></li><li><p>IPEX</p><p>POSM logistics tracking platform</p><ul><li>the logistics/delivery status</li></ul></li><li><p>CDDI</p><p>CD Master data interface system</p><ul><li>customer master data</li></ul></li><li><p>WeChat (Enterprise)</p><p>Cross-functional collaboration tool and information window</p><p>Access Sales Force Empowerment Platform from WeChat (Enterprise) (\u5FAE\u4FE1&amp;\u4F01\u4E1A\u5FAE\u4FE1) for related users and integrate the workflow</p></li></ul><h3 id="\u63A8\u9001" tabindex="-1"><a class="header-anchor" href="#\u63A8\u9001" aria-hidden="true">#</a> \u63A8\u9001</h3><ul><li><p>TPM</p><p>Trade promotion management platform for activities arrangements, budget control, cost estimation and etc.</p><ul><li>application (POSM &amp; PMG) &amp; approval request</li></ul></li><li><p>CDDI</p><p>CD Master data interface system</p><ul><li>customer master data update</li></ul></li></ul><h2 id="\u57FA\u7840\u7BA1\u7406" tabindex="-1"><a class="header-anchor" href="#\u57FA\u7840\u7BA1\u7406" aria-hidden="true">#</a> \u57FA\u7840\u7BA1\u7406</h2><p>Basic Admin</p><h3 id="\u591A\u89D2\u8272\u652F\u6301" tabindex="-1"><a class="header-anchor" href="#\u591A\u89D2\u8272\u652F\u6301" aria-hidden="true">#</a> \u591A\u89D2\u8272\u652F\u6301</h3><p>Multiple Role Support</p><p>The system can support multiple roles of sales, i.e. internal regional SR, distributor shared SR, audit team, supervisor, etc with definable authorization control</p><ul><li><p>\u53EF\u7075\u6D3B\u5B9A\u4E49\u6388\u6743\u63A7\u5236</p></li><li><p>\u89D2\u8272\u4FE1\u606F</p><p>Basic Admin</p><ul><li><p>internal regional SR</p></li><li><p>distributor shared SR</p></li><li><p>audit team</p></li><li><p>supervisor</p><ul><li><p>DAS-\u7ECF\u9500\u5546\u4E1A\u52A1\u4E3B\u4EFB</p><p>Dealers Administration Supervisor</p></li></ul></li><li><p>UL Center Team</p></li><li><p>Internal Sales Team</p></li><li><p>\u5176\u4ED6\u3002\u3002</p></li></ul></li></ul><h3 id="\u53EF\u914D\u7F6E\u5316" tabindex="-1"><a class="header-anchor" href="#\u53EF\u914D\u7F6E\u5316" aria-hidden="true">#</a> \u53EF\u914D\u7F6E\u5316</h3><p>Configurable</p><p>Features are easily configurable for any possible changes of roles and responsibilities in future</p><ul><li>changes of roles and responsibilities</li></ul><p><em>XMind - Trial Version</em></p>',113);function r(t,n){return l}var o=e(a,[["render",r],["__file","UL SFEP.html.vue"]]);export{o as default};
